                $(this).parent().slideUp();
                console.log($(this).parent().find("p"))
                config_never_show.push(new Alert($(this).parent().find("#title").text(),$(this).parent().find("#body").text(),$(this).parent().find("#type").text(),$(this).parent().find("img").prop('outerHTML')));
